@Configuration
class SecurityConfig {

    @Bean
    SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.ignoringRequestMatchers("/saml/acs"))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/saml/acs", "/error").permitAll()
                .anyRequest().authenticated()
            )
            .formLogin(form -> form.disable())
            .httpBasic(Customizer.withDefaults())
            .logout(logout -> logout.logoutUrl("/logout").logoutSuccessUrl("/"))
            .securityContext(ctx -> ctx.requireExplicitSave(false));
        return http.build();
    }
}

@Controller
class HomeController {

    @GetMapping(value = "/", produces = MediaType.TEXT_PLAIN_VALUE)
    @ResponseBody
    public String home(HttpServletRequest request, Principal principal) {
        HttpSession session = request.getSession(false);
        StringBuilder sb = new StringBuilder();
        sb.append("SAML SP is running\n");
        sb.append("Authenticated: ").append(principal != null).append("\n");
        if (principal != null) {
            sb.append("Principal: ").append(principal.getName()).append("\n");
        }
        if (session != null) {
            Enumeration<String> names = session.getAttributeNames();
            while (names.hasMoreElements()) {
                String name = names.nextElement();
                Object value = session.getAttribute(name);
                sb.append(name).append("=").append(value).append("\n");
            }
        }
        return sb.toString();
    }

    @GetMapping(value = "/me", produces = MediaType.APPLICATION_JSON_VALUE)
    @ResponseBody
    public Map<String, Object> me(HttpServletRequest request, Principal principal) {
        Map<String, Object> out = new LinkedHashMap<>();
        out.put("authenticated", principal != null);
        out.put("principal", principal != null ? principal.getName() : null);
        HttpSession session = request.getSession(false);
        if (session != null) {
            Map<String, Object> attrs = new LinkedHashMap<>();
            Enumeration<String> names = session.getAttributeNames();
            while (names.hasMoreElements()) {
                String name = names.nextElement();
                attrs.put(name, session.getAttribute(name));
            }
            out.put("sessionAttributes", attrs);
        }
        return out;
    }
}

@Controller
class SamlAcsController {

    private final SamlResponseProcessor samlResponseProcessor;

    SamlAcsController(SamlResponseProcessor samlResponseProcessor) {
        this.samlResponseProcessor = samlResponseProcessor;
    }

    @PostMapping(value = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public void acs(@RequestParam("SAMLResponse") String samlResponse,
                    @RequestParam(value = "RelayState", required = false) String relayState,
                    HttpServletRequest request,
                    HttpServletResponse response) throws Exception {

        SamlPrincipal principal = samlResponseProcessor.process(samlResponse);

        SamlAuthenticationToken authentication = new SamlAuthenticationToken(principal);
        authentication.setAuthenticated(true);

        SecurityContext context = SecurityContextHolder.createEmptyContext();
        context.setAuthentication(authentication);
        SecurityContextHolder.setContext(context);

        HttpSession session = request.getSession(true);
        session.setAttribute("samlNameId", principal.getName());
        session.setAttribute("samlIssuer", principal.getIssuer());
        session.setAttribute("samlSessionIndex", principal.getSessionIndex());
        session.setAttribute("samlAuthnInstant", principal.getAuthnInstant());
        session.setAttribute("samlAttributes", principal.getAttributes());
        for (Map.Entry<String, List<String>> entry : principal.getAttributes().entrySet()) {
            session.setAttribute("attr:" + entry.getKey(), entry.getValue());
        }

        new HttpSessionSecurityContextRepository().saveContext(context, request, response);

        String target = StringUtils.hasText(relayState) ? relayState : "/me";
        response.sendRedirect(target);
    }
}

@Component
class SamlResponseProcessor {

    public SamlPrincipal process(String base64SamlResponse) throws Exception {
        byte[] decoded = Base64.getDecoder().decode(base64SamlResponse);
        Document document = parseSecureXml(decoded);

        XPath xpath = newXPath();

        String issuer = string(xpath, document, "/*[local-name()='Response']/*[local-name()='Issuer']/text()");
        if (!StringUtils.hasText(issuer)) {
            issuer = string(xpath, document, "//*[local-name()='Assertion']/*[local-name()='Issuer']/text()");
        }

        Node assertionNode = (Node) xpath.evaluate("//*[local-name()='Assertion']", document, XPathConstants.NODE);
        if (assertionNode == null) {
            throw new IllegalArgumentException("No Assertion found in SAMLResponse");
        }

        String nameId = string(xpath, assertionNode, ".//*[local-name()='Subject']/*[local-name()='NameID']/text()");
        if (!StringUtils.hasText(nameId)) {
            nameId = string(xpath, assertionNode, ".//*[local-name()='Attribute' and (@Name='uid' or @FriendlyName='uid')]/*[local-name()='AttributeValue']/text()");
        }
        if (!StringUtils.hasText(nameId)) {
            throw new IllegalArgumentException("No subject identifier found in SAML assertion");
        }

        String sessionIndex = string(xpath, assertionNode, ".//*[local-name()='AuthnStatement']/@SessionIndex");
        String authnInstant = string(xpath, assertionNode, ".//*[local-name()='AuthnStatement']/@AuthnInstant");

        validateTimeConditions(xpath, assertionNode);

        Map<String, List<String>> attributes = extractAttributes(xpath, assertionNode);

        return new SamlPrincipal(nameId, issuer, sessionIndex, authnInstant, attributes);
    }

    private void validateTimeConditions(XPath xpath, Node assertionNode) throws Exception {
        String notBefore = string(xpath, assertionNode, ".//*[local-name()='Conditions']/@NotBefore");
        String notOnOrAfter = string(xpath, assertionNode, ".//*[local-name()='Conditions']/@NotOnOrAfter");
        Instant now = Instant.now();

        if (StringUtils.hasText(notBefore)) {
            Instant nb = Instant.parse(notBefore);
            if (now.isBefore(nb.minusSeconds(60))) {
                throw new IllegalArgumentException("Assertion is not yet valid");
            }
        }

        if (StringUtils.hasText(notOnOrAfter)) {
            Instant noa = Instant.parse(notOnOrAfter);
            if (!now.isBefore(noa.plusSeconds(60))) {
                throw new IllegalArgumentException("Assertion has expired");
            }
        }
    }

    private Map<String, List<String>> extractAttributes(XPath xpath, Node assertionNode) throws Exception {
        Map<String, List<String>> attributes = new LinkedHashMap<>();
        org.w3c.dom.NodeList nodes = (org.w3c.dom.NodeList) xpath.evaluate(
            ".//*[local-name()='AttributeStatement']/*[local-name()='Attribute']",
            assertionNode,
            XPathConstants.NODESET
        );

        for (int i = 0; i < nodes.getLength(); i++) {
            Element attr = (Element) nodes.item(i);
            String name = attr.getAttribute("Name");
            if (!StringUtils.hasText(name)) {
                name = attr.getAttribute("FriendlyName");
            }
            if (!StringUtils.hasText(name)) {
                continue;
            }

            org.w3c.dom.NodeList values = (org.w3c.dom.NodeList) xpath.evaluate(
                "./*[local-name()='AttributeValue']",
                attr,
                XPathConstants.NODESET
            );

            List<String> attrValues = new ArrayList<>();
            for (int j = 0; j < values.getLength(); j++) {
                Node v = values.item(j);
                String text = v.getTextContent();
                if (text != null) {
                    text = text.trim();
                }
                if (StringUtils.hasText(text)) {
                    attrValues.add(text);
                }
            }

            attributes.put(name, attrValues);
        }

        return attributes;
    }

    private Document parseSecureXml(byte[] xmlBytes) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setXIncludeAware(false);
        dbf.setExpandEntityReferences(false);
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        DocumentBuilder db = dbf.newDocumentBuilder();
        return db.parse(new ByteArrayInputStream(xmlBytes));
    }

    private XPath newXPath() {
        XPath xpath = XPathFactory.newInstance().newXPath();
        xpath.setNamespaceContext(new NamespaceContext() {
            @Override
            public String getNamespaceURI(String prefix) {
                if ("saml2".equals(prefix)) {
                    return "urn:oasis:names:tc:SAML:2.0:assertion";
                }
                if ("saml2p".equals(prefix)) {
                    return "urn:oasis:names:tc:SAML:2.0:protocol";
                }
                return XMLConstants.NULL_NS_URI;
            }

            @Override
            public String getPrefix(String namespaceURI) {
                return null;
            }

            @Override
            public Iterator<String> getPrefixes(String namespaceURI) {
                return Collections.emptyIterator();
            }
        });
        return xpath;
    }

    private String string(XPath xpath, Object item, String expression) throws Exception {
        String value = (String) xpath.evaluate(expression, item, XPathConstants.STRING);
        return value != null ? value.trim() : null;
    }
}

class SamlPrincipal implements Principal {
    private final String name;
    private final String issuer;
    private final String sessionIndex;
    private final String authnInstant;
    private final Map<String, List<String>> attributes;

    SamlPrincipal(String name, String issuer, String sessionIndex, String authnInstant, Map<String, List<String>> attributes) {
        this.name = name;
        this.issuer = issuer;
        this.sessionIndex = sessionIndex;
        this.authnInstant = authnInstant;
        this.attributes = new LinkedHashMap<>(attributes);
    }

    @Override
    public String getName() {
        return name;
    }

    public String getIssuer() {
        return issuer;
    }

    public String getSessionIndex() {
        return sessionIndex;
    }

    public String getAuthnInstant() {
        return authnInstant;
    }

    public Map<String, List<String>> getAttributes() {
        return Collections.unmodifiableMap(attributes);
    }
}

class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final SamlPrincipal principal;

    SamlAuthenticationToken(SamlPrincipal principal) {
        super(buildAuthorities(principal));
        this.principal = principal;
        super.setAuthenticated(true);
    }

    private static List<SimpleGrantedAuthority> buildAuthorities(SamlPrincipal principal) {
        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
        List<String> groups = principal.getAttributes().getOrDefault("groups", Collections.emptyList());
        for (String g : groups) {
            String role = g.toUpperCase().replaceAll("[^A-Z0-9_]", "_");
            authorities.add(new SimpleGrantedAuthority("ROLE_" + role));
        }
        return authorities;
    }

    @Override
    public Object getCredentials() {
        return "";
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    @Override
    public String getName() {
        return principal.getName();
    }
}